    69	 */
    70	function reconcileRecords(
    71	  records: Map<string, boolean>,
    72	  visibleGroupIds: string[]
    73	): {changed: boolean; records: Map<string, boolean>} {
    74	  const nextRecords = new Map(records);
    75	  let changed = false;
    76	  const existingIds = new Set(visibleGroupIds);
    77	
    78	  for (const id of records.keys()) {
    79	    if (!existingIds.has(id)) {
    80	      nextRecords.delete(id);
    81	      changed = true;
    82	    }
    83	  }
    84	
    85	  const allSelected = areAllSelected(nextRecords);
    86	
    87	  for (const id of visibleGroupIds) {
    88	    if (!nextRecords.has(id)) {
    89	      nextRecords.set(id, allSelected);
    90	      changed = true;
    91	    }
    92	  }
    93	
    94	  return {changed, records: nextRecords};
    95	}
